if (! function_exists('chart_generator')) {
    function chart_generator($labels, $values, $title = null, $width = null, $height = null, $filename = null, $bar_color = null)
    {
            $labels = $labels ?? [];
            $values = $values ?? [];
            $title = $title ?? '';
            $width = $width ?? 800;
            $height = $height ?? 400;
            $filename = $filename ?? '';
            $bar_color = $bar_color ?? '#3366CC';

            $width = max(200, min(2000, (int)$width));
            $height = max(150, min(1500, (int)$height));

            if (!is_array($labels) || !is_array($values)) {
                return ['success' => false, 'error' => 'Labels and values must be arrays.'];
            }

            if (count($labels) === 0 || count($values) === 0) {
                return ['success' => false, 'error' => 'Labels and values arrays must not be empty.'];
            }

            if (count($labels) !== count($values)) {
                return ['success' => false, 'error' => 'Labels and values arrays must have the same length.'];
            }

            // Max 50 bars
            $count = min(count($labels), 50);
            $labels = array_slice($labels, 0, $count);
            $values = array_slice($values, 0, $count);

            // Check GD
            if (!function_exists('imagecreatetruecolor')) {
                return ['success' => false, 'error' => 'GD library not available.'];
            }

            // Parse bar color
            $hex = ltrim($bar_color, '#');
            if (strlen($hex) === 6) {
                $r = hexdec(substr($hex, 0, 2));
                $g = hexdec(substr($hex, 2, 2));
                $b = hexdec(substr($hex, 4, 2));
            } else {
                $r = 51; $g = 102; $b = 204; // default blue
            }

            // Create canvas
            $img = @imagecreatetruecolor($width, $height);
            if (!$img) {
                return ['success' => false, 'error' => 'Failed to create image canvas.'];
            }

            // Enable alpha blending
            imagealphablending($img, true);

            // Define colors
            $white = imagecolorallocate($img, 255, 255, 255);
            $black = imagecolorallocate($img, 0, 0, 0);
            $gray = imagecolorallocate($img, 200, 200, 200);
            $dark_gray = imagecolorallocate($img, 100, 100, 100);
            $bar_rgb = imagecolorallocate($img, $r, $g, $b);
            $bar_light = imagecolorallocate($img, min(255, $r + 60), min(255, $g + 60), min(255, $b + 60));
            $bg_color = imagecolorallocate($img, 252, 252, 252);
            $axis_color = imagecolorallocate($img, 180, 180, 180);

            // Fill background
            imagefilledrectangle($img, 0, 0, $width, $height, $bg_color);

            // Margins
            $margin_left = 70;
            $margin_right = 30;
            $margin_top = $title ? 60 : 40;
            $margin_bottom = 60;

            $chart_w = $width - $margin_left - $margin_right;
            $chart_h = $height - $margin_top - $margin_bottom;
            $chart_right = $width - $margin_right;
            $chart_bottom = $height - $margin_bottom;

            // Find min/max values
            $max_val = max($values);
            $min_val = min($values);
            $range = $max_val - $min_val;
            if ($range === 0) $range = 1;
            // Scale up max to nice round number
            if ($max_val > 0) {
                $pow = pow(10, floor(log10($max_val)));
                $max_val = ceil($max_val / $pow) * $pow;
                if ($max_val <= 0) $max_val = $pow;
            } else {
                $max_val = 1;
            }
            if ($min_val > 0) $min_val = 0;

            // Draw horizontal gridlines
            $grid_count = 5;
            for ($i = 0; $i <= $grid_count; $i++) {
                $y = $chart_bottom - ($chart_h * $i / $grid_count);
                imageline($img, $margin_left, (int)$y, $chart_right, (int)$y, $axis_color);
                // Y-axis label
                $val = $min_val + ($max_val - $min_val) * $i / $grid_count;
                $label = number_format($val, $val < 10 ? 1 : 0);
                $label_width = strlen($label) * 5;
                imagestring($img, 2, $margin_left - $label_width - 8, (int)$y - 6, $label, $dark_gray);
            }

            // Draw axes
            imageline($img, $margin_left, $margin_top, $margin_left, $chart_bottom, $dark_gray);
            imageline($img, $margin_left, $chart_bottom, $chart_right, $chart_bottom, $dark_gray);

            // Calculate bar dimensions
            if ($count <= 1) {
                $bar_area_width = $chart_w * 0.8;
            } else {
                $bar_area_width = $chart_w * 0.9;
            }
            $bar_width = min(80, ($bar_area_width / $count) * 0.7);
            $bar_gap = ($chart_w - $bar_width * $count) / ($count + 1);
            $bar_start_x = $margin_left + $bar_gap;

            // Draw bars
            for ($i = 0; $i < $count; $i++) {
                $val = $values[$i];
                $bar_h = ($val - $min_val) / ($max_val - $min_val) * $chart_h;
                $x1 = $bar_start_x + $i * ($bar_width + $bar_gap);
                $y1 = $chart_bottom - $bar_h;
                $x2 = $x1 + $bar_width;

                // Draw bar with highlight (light on top)
                imagefilledrectangle($img, (int)$x1, (int)$y1, (int)$x2, $chart_bottom, $bar_rgb);
                // Top highlight
                $highlight_h = min(5, $bar_h * 0.1);
                if ($highlight_h > 1) {
                    imagefilledrectangle($img, (int)$x1, (int)$y1, (int)$x2, (int)($y1 + $highlight_h), $bar_light);
                }

                // X-axis label
                $label_text = $labels[$i];
                // Truncate long labels
                if (strlen($label_text) > 15) $label_text = substr($label_text, 0, 13) . '..';
                $label_center = (int)($x1 + $bar_width / 2 - strlen($label_text) * 2.5);
                imagestring($img, 2, max($margin_left, $label_center), $chart_bottom + 5, $label_text, $dark_gray);

                // Value on top of bar (if bar is tall enough)
                $val_text = number_format($val, $val < 10 ? 1 : 0);
                $val_center = (int)($x1 + $bar_width / 2 - strlen($val_text) * 2.5);
                if ($bar_h > 25) {
                    imagestring($img, 2, max($margin_left, $val_center), (int)($y1 - 14), $val_text, $dark_gray);
                } else {
                    imagestring($img, 2, max($margin_left, $val_center), (int)($y1 + 2), $val_text, $dark_gray);
                }
            }

            // Draw title
            if (!empty($title)) {
                $title_center = (int)($width / 2 - strlen($title) * 3);
                imagestring($img, 5, max(5, $title_center), 12, $title, $black);
            }

            // Draw border
            imagerectangle($img, 0, 0, $width - 1, $height - 1, $gray);

            // Save image
            $workspace = __DIR__ . '/../workspace';
            if (!is_dir($workspace)) @mkdir($workspace, 0777, true);

            $auto_filename = $filename ?: 'chart-' . gmdate('Ymd-His') . '.png';
            if (!str_ends_with(strtolower($auto_filename), '.png')) $auto_filename .= '.png';
            $output_path = $workspace . '/' . basename($auto_filename);

            $saved = @imagepng($img, $output_path);
            $filesize = @filesize($output_path);
            imagedestroy($img);

            if (!$saved) {
                return ['success' => false, 'error' => 'Failed to save chart image.'];
            }

            return [
                'success' => true,
                'filename' => 'storage/agent/workspace/' . basename($auto_filename),
                'file_size_bytes' => $filesize,
                'dimensions' => "{$width}x{$height}",
                'bars' => $count,
                'max_value' => $max_val,
                'min_value' => $min_val,
                'chart_title' => $title ?: '(none)',
                'bar_color' => $bar_color,
                'image_type' => 'PNG',
            ];
    }
